(function () {
    "use strict";
    let isInitialized = false;

    const initSearch = () => {
        if (isInitialized) return;

        const toggleBtns = document.querySelectorAll(".search-toggle");
        const searchBar = document.querySelector(".search-bar");
        const closeBtn = document.querySelector(".search-close");
        const searchInput = document.getElementById("siteSearch");
        const resultsContainer = document.getElementById("searchResults");
        let latestResults = [];

        if (!searchBar || !searchInput) {
            if (!window.searchObserver) {
                window.searchObserver = new MutationObserver((mutations, obs) => {
                    if (document.querySelector(".search-toggle")) {
                        initSearch();
                        obs.disconnect();
                        delete window.searchObserver;
                    }
                });
                window.searchObserver.observe(document.body, { childList: true, subtree: true });
            }
            return;
        }

        isInitialized = true;

        // ── Helpers ──────────────────────────────────────────────────────────────

        const escapeRegExp = (value) => value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

        const getIconClass = (item) => {
            const text = (item.title + " " + item.tags).toLowerCase();
            if (text.includes("audit")) return "fa-clipboard-check";
            if (text.includes("energy")) return "fa-leaf";
            if (text.includes("safety") || text.includes("fire")) return "fa-shield-alt";
            if (text.includes("hvac") || text.includes("ventilation")) return "fa-wind";
            if (text.includes("electrical") || text.includes("power")) return "fa-bolt";
            if (text.includes("compli")) return "fa-file-signature";
            if (text.includes("solar") || text.includes("renew")) return "fa-sun";
            if (text.includes("water")) return "fa-faucet-drip";
            if (text.includes("waste")) return "fa-recycle";
            if (text.includes("project")) return "fa-project-diagram";
            if (text.includes("blog")) return "fa-newspaper";
            if (text.includes("contact")) return "fa-envelope-open-text";
            if (text.includes("client")) return "fa-users";
            return "fa-arrow-right";
        };

        const getPageType = (item) => {
            const url = (item.url || "").toLowerCase();
            const text = `${item.title || ""} ${item.tags || ""}`.toLowerCase();
            if (url.startsWith("/blog/")) return "blog";
            if (url === "/service" || url === "/services" || url.startsWith("/services/") || text.includes("product")) return "service";
            return "static";
        };

        const getTypePriority = (type) => {
            if (type === "service") return 3;
            if (type === "static") return 2;
            return 1; // blog
        };

        const getUrlKey = (item) => (item.url || "").replace(/\/+$/, "").toLowerCase() || "/";

        /**
         * Generate a short, relevant snippet for a result.
         * Picks the best sentence/fragment around the first term match.
         */
        const generateSnippet = (text, query, terms) => {
            if (!text || !query) return "";
            const lowerText = text.toLowerCase();

            // Find best term to anchor the snippet
            let anchorTerm = terms.find(t => t.length > 1 && lowerText.includes(t));
            if (!anchorTerm) return "";

            const index = lowerText.indexOf(anchorTerm);
            if (index === -1) return "";

            const halfWindow = 80;
            const start = Math.max(0, index - halfWindow);
            const end = Math.min(text.length, index + anchorTerm.length + halfWindow);

            let snippet = text.substring(start, end).trim();
            if (start > 0) snippet = "\u2026" + snippet;
            if (end < text.length) snippet = snippet + "\u2026";

            // Highlight all matched terms
            const escapedTerms = [query, ...terms]
                .filter(t => t.length > 1)
                .map(escapeRegExp);
            const regex = new RegExp(`(${escapedTerms.join("|")})`, "gi");
            return snippet.replace(regex, "<mark>$1</mark>");
        };

        // ── Matching: page is included ONLY if title / URL / tags match ──────────
        // Text-body is used for scoring only, preventing common words from
        // matching every page that incidentally mentions them.
        const scoreItem = (item, query, terms) => {
            const titleLower = item.title ? item.title.toLowerCase() : "";
            const tagsLower = item.tags ? item.tags.toLowerCase() : "";
            const textLower = item.text ? item.text.toLowerCase() : "";
            const urlLower = item.url ? item.url.toLowerCase() : "";
            const slugQuery = query.replace(/\s+/g, "-");

            // -- Primary match signals (required for inclusion) -------------------
            const titleExact = titleLower === query;
            const titleMatch = titleLower.includes(query);
            const urlMatch = urlLower.includes(query) || urlLower.includes(slugQuery);
            const tagsMatch = tagsLower.includes(query);

            // Per-term title/url/tag hits (for partial-word queries like "about us")
            const termTitleHits = terms.filter(t => t.length > 1 && titleLower.includes(t));
            const termTagHits = terms.filter(t => t.length > 1 && tagsLower.includes(t));
            const termUrlHits = terms.filter(t => t.length > 1 && urlLower.includes(t));

            // A page qualifies for inclusion if it matches at the title/url/tags level
            const primaryMatch =
                titleMatch || urlMatch || tagsMatch ||
                termTitleHits.length > 0 || termTagHits.length > 0 || termUrlHits.length > 0;

            if (!primaryMatch) return null;

            // -- Scoring ----------------------------------------------------------
            const type = getPageType(item);
            let score = getTypePriority(type) * 10000;

            if (titleExact) score += 2000;
            if (titleMatch) score += 1200;
            if (urlMatch) score += 900;
            if (tagsMatch) score += 650;

            termTitleHits.forEach(() => { score += 260; });
            termTagHits.forEach(() => { score += 160; });
            termUrlHits.forEach(() => { score += 120; });

            // Bonus: text body contains term (boosts score, does NOT gate inclusion)
            terms.forEach(term => {
                if (term.length > 2 && textLower.includes(term)) score += 40;
            });

            return score;
        };

        // ── Render ───────────────────────────────────────────────────────────────

        const renderResultItem = (item, index, query, terms) => {
            const iconClass = getIconClass(item);
            const delay = index * 0.05;
            const snippet = generateSnippet(item.text || "", query, terms);
            const excerptHtml = snippet
                ? `<div class="result-excerpt" style="font-size:0.85em;color:#666;margin-top:4px;line-height:1.4;">${snippet}</div>`
                : "";

            return `
            <a href="${item.url}" class="search-result-item" style="animation-delay:${delay}s;display:flex;align-items:flex-start;padding:12px;border-bottom:1px solid #eee;text-decoration:none;color:inherit;transition:background 0.2s;">
                <div class="result-icon" style="margin-right:15px;color:var(--primary-color,#0056b3);font-size:1.2em;padding-top:2px;"><i class="fas ${iconClass}"></i></div>
                <div class="result-info" style="flex:1;">
                    <span class="result-title" style="display:block;font-weight:600;margin-bottom:2px;">${item.title}</span>
                    <span class="result-url" style="display:block;font-size:0.8em;color:#888;margin-bottom:2px;">${item.url}</span>
                    ${excerptHtml}
                </div>
                <div class="result-arrow" style="margin-left:10px;color:#ccc;"><i class="fas fa-chevron-right"></i></div>
            </a>`;
        };

        const renderResultSection = (title, items, query, terms) => {
            if (items.length === 0) return "";
            const rows = items.map((item, i) => renderResultItem(item, i, query, terms)).join("");
            return `
            <div class="search-result-section" style="margin-bottom:22px;">
                <div class="search-suggestions-header" style="padding:10px 15px;font-size:0.85em;font-weight:600;text-transform:uppercase;color:#888;background:#f9f9f9;">${title}</div>
                <div class="search-section-results">${rows}</div>
            </div>`;
        };

        // ── Suggestions (empty state) ─────────────────────────────────────────────

        const showSuggestions = () => {
            if (typeof SEARCH_DATA === "undefined") return;
            const suggestionTerms = ["Energy Audit", "Electrical Safety", "HVAC Projects", "Fire Fighting", "Solar LED Systems"];
            const suggestions = SEARCH_DATA
                .filter(item => suggestionTerms.some(term => item.title.includes(term)))
                .slice(0, 6);

            resultsContainer.innerHTML = `
                <div class="search-suggestions-header" style="padding:10px 15px;font-size:0.85em;font-weight:600;text-transform:uppercase;color:#888;background:#f9f9f9;">Quick Search Suggestions</div>
                <div class="search-suggestions-container">
                    ${suggestions.map((item, i) => renderResultItem(item, i, "", [])).join("")}
                </div>`;
        };

        // ── Open / Close ─────────────────────────────────────────────────────────

        const openSearch = () => {
            searchBar.classList.add("active");
            document.body.style.overflow = "hidden";
            setTimeout(() => {
                searchInput.focus();
                if (searchInput.value.trim() === "") showSuggestions();
            }, 100);
        };

        const closeSearch = () => {
            searchBar.classList.remove("active");
            document.body.style.overflow = "";
            setTimeout(() => {
                searchInput.value = "";
                resultsContainer.innerHTML = "";
            }, 300);
        };

        // ── Event Wiring ─────────────────────────────────────────────────────────

        toggleBtns.forEach(btn => {
            btn.addEventListener("click", e => { e.preventDefault(); e.stopPropagation(); openSearch(); });
        });

        if (closeBtn) {
            closeBtn.addEventListener("click", e => { e.preventDefault(); e.stopPropagation(); closeSearch(); });
        }

        document.addEventListener("keydown", e => {
            if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === "k") { e.preventDefault(); openSearch(); }
            if (e.key === "Escape" && searchBar.classList.contains("active")) closeSearch();
        });

        searchInput.addEventListener("keydown", e => {
            if (e.key === "Enter" && latestResults.length > 0) {
                e.preventDefault();
                window.location.href = latestResults[0].url;
            }
        });

        searchBar.addEventListener("click", e => {
            if (e.target === searchBar) closeSearch();
        });

        // ── Core Search ──────────────────────────────────────────────────────────

        const updateUrl = (query) => {
            const url = new URL(window.location);
            if (query) { url.searchParams.set("q", query); }
            else { url.searchParams.delete("q"); }
            window.history.replaceState({}, "", url);
        };

        const performSearch = (query) => {
            if (query.length === 0) { latestResults = []; showSuggestions(); updateUrl(query); return; }
            if (query.length < 2) { latestResults = []; resultsContainer.innerHTML = ""; updateUrl(query); return; }

            if (typeof SEARCH_DATA === "undefined") {
                resultsContainer.innerHTML = '<div class="search-no-results" style="padding:30px;text-align:center;color:#666;">Initializing search data…</div>';
                return;
            }

            updateUrl(query);

            const terms = query.split(/\s+/).filter(Boolean);

            // Score every page; pages that don't match title/url/tags are excluded
            const scored = [];
            const seenUrls = new Set();

            SEARCH_DATA.forEach((item, originalIndex) => {
                const urlKey = getUrlKey(item);
                if (seenUrls.has(urlKey)) return; // deduplicate at source

                const score = scoreItem(item, query, terms);
                if (score === null) return;

                seenUrls.add(urlKey);
                scored.push({ ...item, _score: score, _index: originalIndex, _type: getPageType(item) });
            });

            // Sort: higher score first; ties broken by original order
            scored.sort((a, b) => (b._score - a._score) || (a._index - b._index));

            // Split into primary (services + static) and blog sections
            const primaryResults = scored.filter(r => r._type !== "blog").slice(0, 10);
            const blogResults = scored.filter(r => r._type === "blog").slice(0, 6);
            latestResults = [...primaryResults, ...blogResults];

            if (latestResults.length > 0) {
                resultsContainer.innerHTML =
                    renderResultSection("Services, Products & Pages", primaryResults, query, terms) +
                    renderResultSection("Blog Posts", blogResults, query, terms);
            } else {
                resultsContainer.innerHTML = `
                <div class="search-no-results" style="padding:40px 20px;text-align:center;color:#555;">
                    <i class="fas fa-search-minus" style="font-size:3rem;color:#ddd;margin-bottom:20px;display:block;"></i>
                    No results found for "<strong>${query}</strong>"<br>
                    <span style="font-size:0.9rem;margin-top:10px;display:block;opacity:0.7;">Try searching for "Audit", "HVAC", or "Safety"</span>
                </div>`;
            }
        };

        searchInput.addEventListener("input", e => {
            performSearch(e.target.value.toLowerCase().trim());
        });

        // ── Restore from URL on page load ─────────────────────────────────────────
        const urlParams = new URLSearchParams(window.location.search);
        const queryParam = urlParams.get("q");
        if (queryParam) {
            openSearch();
            searchInput.value = queryParam;
            performSearch(queryParam.toLowerCase().trim());
        }
    };

    window.initializeSearchEngine = initSearch;

    // Add tap-to-show client name on mobile
    document.addEventListener('DOMContentLoaded', () => {
        const clientItems = document.querySelectorAll('.client-item');
        clientItems.forEach(item => {
            item.addEventListener('click', (e) => {
                // Remove active from all items
                clientItems.forEach(i => i.classList.remove('active'));
                // Add active to the clicked item
                item.classList.add('active');
                // Auto-close after 3 seconds
                setTimeout(() => item.classList.remove('active'), 3000);
            });
        });
    });

    if (document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", initSearch);
    } else {
        initSearch();
    }
})();
